// permissionGroup represents a resource and its associated actions.
type permissionGroup struct {
	Resource string
	Actions  []string
}

// groupPermissionsByResource groups permissions by their resource field
// and returns them sorted alphabetically by resource name.
func groupPermissionsByResource(perms []*rbac.Permission) []permissionGroup {
	m := make(map[string][]string)
	for _, p := range perms {
		m[p.Resource] = append(m[p.Resource], p.Action)
	}

	groups := make([]permissionGroup, 0, len(m))
	for res, actions := range m {
		sort.Strings(actions)
		groups = append(groups, permissionGroup{Resource: res, Actions: actions})
	}
	sort.Slice(groups, func(i, j int) bool {
		return groups[i].Resource < groups[j].Resource
	})
	return groups
}

// actionBadgeVariant returns a badge variant based on the action type.
func actionBadgeVariant(action string) badge.Variant {
	switch action {
	case "admin", "delete":
		return badge.VariantDestructive
	case "write", "create", "update":
		return badge.VariantDefault
	default:
		return badge.VariantSecondary
	}
}

// actionWord returns "action" or "actions" based on count.
func actionWord(count int) string {
	if count == 1 {
		return "action"
	}
	return "actions"
}

